<script setup lang="ts">
import { ref } from 'vue'
import { api, APIError } from '@/api/client'
const steamId = ref(''); const password = ref(''); const confirmPassword = ref(''); const busy = ref(false); const error = ref<string|null>(null); const submitted = ref(false)
async function submit() { error.value = null; if (password.value !== confirmPassword.value) { error.value = '两次输入的密码不一致。'; return }; busy.value = true; try { await api.auth.register(steamId.value, password.value, confirmPassword.value); submitted.value = true; password.value = ''; confirmPassword.value = '' } catch(value) { const messages:Record<string,string>={player_not_online:'未找到当前在线角色，请先进入本 Palworld 服务器并保持在线。',palworld_unavailable:'Palworld API 暂时不可用，未创建申请。',duplicate_account:'该玩家身份已经存在账号或申请。'}; error.value = value instanceof APIError ? messages[value.code] ?? value.message : '申请失败，请重试。' } finally { busy.value = false } }
</script>
<template><div class="simple-page auth-page"><p class="eyebrow">PLAYER APPLICATION</p><h1>申请玩家账号</h1><section class="section-block prose-card"><div v-if="submitted" class="notice success">申请已提交。管理员批准后才能登录。</div><form v-else class="auth-form" @submit.prevent="submit"><p><strong>请先进入本 Palworld 服务器并保持在线，然后提交注册申请。</strong>管理员批准后才能登录。</p><label>SteamID64<input v-model.trim="steamId" inputmode="numeric" pattern="[0-9]+" autocomplete="username" required /></label><label>密码<input v-model="password" type="password" autocomplete="new-password" minlength="8" maxlength="128" required /></label><label>确认密码<input v-model="confirmPassword" type="password" autocomplete="new-password" minlength="8" maxlength="128" required /></label><div v-if="error" class="notice danger">{{ error }}</div><button class="primary-button" :disabled="busy">{{ busy ? '正在核对在线角色…' : '提交申请' }}</button></form><RouterLink class="text-link" to="/login">返回登录 →</RouterLink></section></div></template>
